step.action:
Load scoring thresholds and weights from workflow config:
      - confident threshold = {score_threshold_confident}
      - partial threshold = {score_threshold_partial}
      - minimum repo coverage percent = {minimum_repo_coverage_percent}
      - weights = skills:{weight_skill_coverage}, understanding:{weight_project_understanding}, docs+ticketing:{weight_documentation_ticket_readiness}, testability:{weight_testability_readiness}, operability:{weight_operational_readiness}

Write Markdown report to {{confidence_report_md}} in {{document_language}}:

      # Project Understanding Confidence Report — {{date}}

      ## Verdict
      - Coverage gate: {{coverage_gate_failed ? "FAILED" : "PASSED"}}
      - Repo coverage: {{repo_coverage_percent}}%
      - Global score: {{global_confidence_score}} / 100 (raw: {{raw_global_confidence_score}})
      - Confidence level: {{confidence_verdict}}
      - Assistant mode: {{assistant_mode}}

      ## Repo Coverage Matrix
      {{repo_coverage_matrix}}

      ## Dimension Scores
      - skill_coverage: {{skill_coverage}}
      - project_understanding: {{project_understanding}}
      - documentation_ticket_readiness: {{documentation_ticket_readiness}}
      - testability_readiness: {{testability_readiness}}
      - operational_readiness: {{operational_readiness}}

      ## Critical Gaps
      {{critical_gaps}}

      ## Recommended Gaps
      {{recommended_gaps}}

      ## Action Backlog
      {{action_backlog}}

      ## Confidence Boost Plan
      {{confidence_boost_plan}}

step.output:
[CONFIDENCE] ✅ COMPLETE
├─ Verdict: {{confidence_verdict}}
├─ Score: {{global_confidence_score}} / 100
├─ Coverage: {{repo_coverage_percent}}%
├─ Markdown: {{confidence_report_md}}
├─ JSON: {{confidence_report_json}}
└─ Snapshot: {{workflow_snapshot_md}}
